require("Basic")require("ProtoMgr")require("Net.NetCore.RequestClientHandler")local a=require("PrintTable")local b=require("cjson")require("TimeMgr")local c=Basic.Enum({'NULL','NOTIFY','REQUEST','RESPONSE'})ChatSocket={}function ChatSocket:New()local d={}setmetatable(d,{__index=ChatSocket})d:Init()return d end;function ChatSocket:Init()self.url=''self.net_connect=nil;self.index=0;self.requestIndex=0;self.clientHandler=RequestClientHandler:New()self.msgListener={}self.msgLst={}self.msgHead=1;self.msgTail=1;self.whenOpen={}self.whenError={}self.whenClose={}self.rpclist={}self.last_heart_beat=-1;self.heart_beat_timer=TimerMgr:Init()local e=self end;function ChatSocket:Connect(f,g)local e=self;if not self.net_connect then self.net_connect=NetConnectSharp(function(h)self:CheckMsg(h)end)self.net_connect.OnOpen=self.net_connect.OnOpen+function(i,j)e:OnOpenSuccess()end;self.net_connect.OnClose=self.net_connect.OnClose+function(i,j)e:OnClose(j)end;self.net_connect.OnError=self.net_connect.OnError+function(i,j)e:OnError(j)end end;local k={}if g then table.insert(k,'ws')end;LogTool.Info('ChatSocket','socket connect: '..f..' '..debug.traceback())self.net_connect:Connect(f,k)self.heart_beat_timer:ClearAllTimers()self.clientHandler:Clear()self.url=f end;function ChatSocket:Close()LogTool.Info('ChatSocket','websocket close')if self.net_connect then self.net_connect:Close()end;self.heart_beat_timer:ClearAllTimers()end;function ChatSocket:OnOpenSuccess()LogTool.Info('ChatSocket','websocket open')if self.whenOpen then for l=1,#self.whenOpen do self.whenOpen[l]()end end;self.heart_beat_timer:ClearAllTimers()self.heart_beat_timer:Loop(20,-1,function()self:SendHeartBeat()end)end;function ChatSocket:OnClose(j)LogTool.Info('ChatSocket','websocket close: '..a.block(j))if self.whenClose then for l=1,#self.whenClose do self.whenClose[l]()end end;self.heart_beat_timer:ClearAllTimers()end;function ChatSocket:OnError(j)LogTool.Info('ChatSocket','websocket error'..a.block(j))if self.whenError then for l=1,#self.whenError do self.whenError[l](j)end end;self.heart_beat_timer:ClearAllTimers()end;local m=1;function ChatSocket:CheckMsg(h)local n=h.RawData;local o=string.match(n,'=>')LogTool.Info('ChatSocket','接收到消息：'..a.block(h)..' '..tostring(n))if not o then LogTool.Error('ChatSocket','收到的消息数据格式有问题:'..tostring(n))else local p=Tools.Split(string.gsub(n,'=>',''),' ')if#p<2 then LogTool.Error('ChatSocket','收到的消息数据格式有问题:'..tostring(n))return end;local q=p[2]if#p>=3 then for l=3,#p do q=q..' '..p[l]end end;local r=nil;r=b.decode(q)if p[1]~='system'then r.type=2 end;for l=1,#self.msgListener['chatupdate']do self.msgListener['chatupdate'][l](p[1],r)end end end;function ChatSocket:SendSysMsg(h)for l=1,#self.msgListener['chatupdate']do self.msgListener['chatupdate'][l]('client_system',h)end end;function ChatSocket:AddListener_Open(s)table.insert(self.whenOpen,s)end;function ChatSocket:AddListener_Close(s)table.insert(self.whenClose,s)end;function ChatSocket:AddListener_Error(s)table.insert(self.whenError,s)end;function ChatSocket:SendHeartBeat()local t='<= heartbeat -'LogTool.InfoNet("ChatSocket","发送心跳")self.net_connect:SendRequest(t,function(u,v)if not u then LogTool.InfoNet("ChatSocket","HeartBeat Fail")return else LogTool.InfoNet("ChatSocket","HeartBeat Connect")end end)end;function ChatSocket:SendMessage(w,x)local t='<= message '..b.encode(w)LogTool.InfoNet("ChatSocket","发送玩家消息, data: "..t)self.net_connect:SendRequest(t,function(u,v)if not u then LogTool.InfoNet("ChatSocket","发送玩家消息失败")if not v then x(Tools.StrOfLocalization(12)..'..',nil)else x(v,nil)end;return else LogTool.InfoNet("ChatSocket","发送玩家消息成功")x(nil,nil)end end)end;function ChatSocket:AddMsgListener(y,s)if not self.msgListener[y]then self.msgListener[y]={}end;table.insert(self.msgListener[y],s)end;function ChatSocket:RemoveMsgListener(y,s)if not self.msgListener[y]then return end;for l=1,#self.msgListener[y]do if self.msgListener[y][l]==s then table.remove(self.msgListener[y],l)break end end end;retur